#!/bin/bash
# Platform run.sh for H009_combined_xattn_dcn_v2.
# CLAUDE.md §17.2 stacking sub-H: H007 (candidate-aware xattn, sequence axis)
# + H008 (DCN-V2 fusion swap, interaction axis) 동시 적용. additivity 가정 검증
# + §0 두 축 동시 강화 first direct verification. 두 mechanism 모두
# MultiSeqHyFormerBlock 안 작동 → block-level gradient sharing (§0 P1 직접
# 충족, concat-late anti-pattern 회피).
# §17.4 hybrid (target_attention + sparse_feature_cross), 정당화 = stacking.
# §18 inference 인프라 룰 inherit.
# Generated by skills/_helpers/build_cloud_package.py — do not hand-edit on platform.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
export PYTHONPATH="${SCRIPT_DIR}:${PYTHONPATH:-}"

# ---------------------------------------------------------------------------
# Platform must set TRAIN_DATA_PATH and TRAIN_CKPT_PATH. Other paths derive.
# ---------------------------------------------------------------------------
: "${TRAIN_DATA_PATH:?TRAIN_DATA_PATH not set by platform}"
: "${TRAIN_CKPT_PATH:?TRAIN_CKPT_PATH not set by platform}"
: "${TRAIN_LOG_PATH:=${TRAIN_CKPT_PATH}/logs}"
: "${TRAIN_TF_EVENTS_PATH:=${TRAIN_CKPT_PATH}/tf_events}"
: "${TRAIN_WORK_PATH:=${TRAIN_CKPT_PATH}/work}"
mkdir -p "${TRAIN_CKPT_PATH}" "${TRAIN_LOG_PATH}" "${TRAIN_TF_EVENTS_PATH}" "${TRAIN_WORK_PATH}"
export TRAIN_LOG_PATH TRAIN_TF_EVENTS_PATH

echo "[run.sh] DATA=${TRAIN_DATA_PATH}"
echo "[run.sh] CKPT=${TRAIN_CKPT_PATH}"
echo "[run.sh] mode=combined-xattn-dcn-v2 + leak-fix (H007 candidate xattn + H008 DCN-V2 fusion stacking)"

# ---------------------------------------------------------------------------
# Train (anchor envelope + H007 + H008 stacking).
# Diff vs original_baseline/run.sh:
#   --use_candidate_summary_token    H007: per-domain CandidateSummaryToken
#   --fusion_type dcn_v2             H008: RankMixerBlock → DCNV2CrossBlock
#   --dcn_v2_num_layers 2            polynomial degree 3 (paper default)
#   --dcn_v2_rank 8                  low-rank approx D/8 (paper guidance)
#   --num_epochs 10 --patience 3     extended envelope, H008 F-4 carry-forward
#   --train_ratio 0.3                extended (paired with H006/H007/H008)
# ---------------------------------------------------------------------------
python3 -u "${SCRIPT_DIR}/train.py" \
    --num_epochs 10 \
    --patience 3 \
    --seed 42 \
    --ns_tokenizer_type rankmixer \
    --user_ns_tokens 5 \
    --item_ns_tokens 2 \
    --num_queries 2 \
    --ns_groups_json "" \
    --emb_skip_threshold 1000000 \
    --num_workers 2 \
    --buffer_batches 4 \
    --train_ratio 0.3 \
    --seq_max_lens "seq_a:64,seq_b:64,seq_c:128,seq_d:128" \
    --use_label_time_split \
    --oof_user_ratio 0.1 \
    --split_seed 42 \
    --use_candidate_summary_token \
    --fusion_type dcn_v2 \
    --dcn_v2_num_layers 2 \
    --dcn_v2_rank 8 \
    "$@"

echo "[run.sh] training complete (combined-xattn-dcn-v2); metrics at ${TRAIN_CKPT_PATH}/metrics.json"
